import{_ as i,c as l,o as r,ah as t,ai as e}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"91GIT - GitHub 중국 중계소","description":"","frontmatter":{},"headers":[],"relativePath":"ko/91git.md","filePath":"ko/91git.md"}'),n={name:"ko/91git.md"};function o(s,a,h,d,c,_){return r(),l("div",null,a[0]||(a[0]=[t('<h1 id="_91git-github-중국-중계소" tabindex="-1">91GIT - GitHub 중국 중계소 <a class="header-anchor" href="#_91git-github-중국-중계소" aria-label="Permalink to “91GIT - GitHub 중국 중계소”">​</a></h1><p><strong>접속 URL:</strong> <a href="https://91git.com/" target="_blank" rel="noreferrer">https://91git.com/</a></p><h2 id="_01-1-프로젝트-개요" tabindex="-1">01.1- 프로젝트 개요 <a class="header-anchor" href="#_01-1-프로젝트-개요" aria-label="Permalink to “01.1- 프로젝트 개요”">​</a></h2><p>GitHub 중국 중계소 —— GitHub 저장소를 원클릭으로 검색하고, 소스 코드와 릴리스 자산을 자동 패키징하여 다운로드용 압축 파일을 생성합니다.</p><p>국내 네트워크 환경에 특화하여 설계되어 개발자가 GitHub 프로젝트 리소스에 신속하게 접근할 수 있도록 지원합니다.</p><p><img src="'+e+'" alt="alt text"></p><h2 id="_01-2-기능-특징" tabindex="-1">01.2- 기능 특징 <a class="header-anchor" href="#_01-2-기능-특징" aria-label="Permalink to “01.2- 기능 특징”">​</a></h2><ul><li>🔍 <strong>키워드 검색</strong> - 키워드로 GitHub 저장소를 검색하고, Star 수로 정렬</li><li>📥 <strong>원클릭 패키징</strong> - 소스 코드 + 릴리스 자산을 자동 다운로드하여 이중 암호화 압축 파일 생성</li><li>🔥 <strong>GitHub 인기</strong> - 이번 주에 새로 생성된 고Star 저장소 Top 10 표시</li><li>📊 <strong>사이트 인기 패키지</strong> - 당일/당월 패키징 횟수가 가장 많은 저장소 표시</li><li>⏱️ <strong>자동 정리</strong> - 패키지 파일은 다운로드되지 않는 경우 3분 후에 자동 삭제, 서버 공간 절약</li></ul><h2 id="_01-3-기술-스택" tabindex="-1">01.3- 기술 스택 <a class="header-anchor" href="#_01-3-기술-스택" aria-label="Permalink to “01.3- 기술 스택”">​</a></h2><ul><li><strong>프론트엔드</strong>: React + TypeScript + Vite + Tailwind CSS</li><li><strong>애니메이션</strong>: Framer Motion</li><li><strong>백엔드</strong>: Node.js + Express</li><li><strong>패키징</strong>: archiver (ZIP)</li><li><strong>암호화</strong>: AES-256 + ZIP 비밀번호</li></ul><h2 id="_01-4-사용-사례" tabindex="-1">01.4- 사용 사례 <a class="header-anchor" href="#_01-4-사용-사례" aria-label="Permalink to “01.4- 사용 사례”">​</a></h2><h3 id="개발자용" tabindex="-1">개발자용 <a class="header-anchor" href="#개발자용" aria-label="Permalink to “개발자용”">​</a></h3><ul><li>GitHub 프로젝트의 소스 코드를 신속하게 획득</li><li>완전한 릴리스 자산 다운로드</li><li>프로젝트 리소스를 패키징하여 공유</li></ul><h3 id="연구자용" tabindex="-1">연구자용 <a class="header-anchor" href="#연구자용" aria-label="Permalink to “연구자용”">​</a></h3><ul><li>연구 도구를 일괄 다운로드</li><li>오픈소스 프로젝트를 아카이브</li><li>로컬 리소스 라이브러리 구축</li></ul><h3 id="기업-사용자용" tabindex="-1">기업 사용자용 <a class="header-anchor" href="#기업-사용자용" aria-label="Permalink to “기업 사용자용”">​</a></h3><ul><li>개발 도구를 사내에서 공유</li><li>팀 리소스 동기화</li><li>오프라인 환경에 배포</li></ul><h2 id="_01-5-보안" tabindex="-1">01.5- 보안 <a class="header-anchor" href="#_01-5-보안" aria-label="Permalink to “01.5- 보안”">​</a></h2><ul><li>✅ 이중 암호화 보호</li><li>✅ 자동 파일 정리</li><li>✅ 사용자 데이터 수집 없음</li><li>✅ 안전한 전송 프로토콜</li></ul><h2 id="_01-6-피드백" tabindex="-1">01.6- 피드백 <a class="header-anchor" href="#_01-6-피드백" aria-label="Permalink to “01.6- 피드백”">​</a></h2><p>질문이나 제안이 있으시면 다음 방법으로 문의해 주세요:</p><ul><li>GitHub Issues</li><li>이메일 피드백</li><li>온라인 고객 서비스</li></ul><hr><p><strong>면책 조항</strong>: 본 도구는 학습 및 연구 목적으로만 사용하세요. GitHub의 이용 약관 및 관련 법규를 준수하세요.</p>',24)]))}const u=i(n,[["render",o]]);export{b as __pageData,u as default};
